+// KillServer terminates the entire tmux server and all sessions.
+func (t *Tmux) KillServer() error {
+	_, err := t.run("kill-server")
+	if errors.Is(err, ErrNoServer) {
+		return nil // Already dead
+	}
+	return err
+}
